import { ParserRegistry } from "../../../core/parser-registry";
import { _polarDomain as domain } from "./polar-domain-marks";
import { _polarSubticksGroup as subticks } from "./polar-subticks-marks";
import { _polarTicksGroup as ticks } from "./polar-ticks-marks";

export function _mainPolaraxis(data) {
    // collect .axis-group marks here
    const subticksMark = subticks.call(this, data);
    const ticksMark = ticks.call(this, data);
    const domainMarks = domain.call(this, data);

    let _mainPolarAxisMark = [
        subticksMark, ticksMark, domainMarks
    ]

    return _mainPolarAxisMark;
}

ParserRegistry.axis('polar.default', _mainPolaraxis);